            count += 1
        else:
            count = 0
            result2.append(letter)
    result3 = []
    count = 0
    for letter in result2:
        if letter == '_' and count < 2:
            count += 1
        else:
            count = 0
            result3.append(letter)
    result3.reverse()
    result3 = ''.join(result3)
    return result3

